using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class EchoTool
{
    [McpServerTool, Description("Echoes the input message back to the caller.")]
    public static string Echo([Description("The message to echo")] string message)
        => $"Echo: {message}";
}

using ModelContextProtocol.Server;

namespace McpHttpServer.Resources;

public class ConfigResource : McpServerResource
{
    public ConfigResource()
    {
        Name = "app-config";
        Uri = "config://app/settings";
        Description = "Returns application configuration data.";
        MimeType = "application/json";
    }

    public override ValueTask<McpServerResourceResponse> ReadAsync(
        RequestContext<McpServerDI> context,
        CancellationToken cancellationToken = default)
    {
        var json = """
            {
              "environment": "production",
              "version": "1.0.0",
              "features": {
                "darkMode": true,
                "notifications": true
              }
            }
            """;

        return ValueTask.FromResult(new McpServerResourceResponse(json, MimeType));
    }
}

